private boolean shouldRetraverse(Node node) {
  if(!nodeChanged && !changedThisIteration) {
    return false;
  } else {
    resetChanges();
    return true;
  }
}

private void resetChanges(){
  this.nodeChanged = false;
  this.changedThisIteration = false;
}

private boolean shouldVisit(Node node){
  switch(node.getType()) {
    case NodeType.RETURN_STATEMENT:
    case NodeType.VAR:
    case NodeType.FUNCTION:
    case NodeType.ARROW_FUNCTION:
    case NodeType.CALL:
    case NodeType.IF:
    case NodeType.WHILE:
    case NodeType.FOR:
    case NodeType.OBJECT_LITERAL:
    case NodeType.ARRAY_LITERAL:
      return true;
    default:
      return false;
  }
}

public class NodeType{
  public static final int RETURN_STATEMENT = 1;
  public static final int VAR = 2;
  public static final int FUNCTION = 3;
  public static final int ARROW_FUNCTION = 4;
  public static final int CALL = 5;
  public static final int IF = 6;
  public static final int WHILE = 7;
  public static final int FOR = 8;
  public static final int OBJECT_LITERAL = 9;
  public static final int ARRAY_LITERAL = 10;

  private NodeType(){}
}

